// Read the last processed Telegram update_id from a small state file. A FILE is
// used on purpose (not n8n static data): static data is not persisted on manual
// test runs, which would replay messages and double-handle commands. The file
// works identically for manual and scheduled (active) executions.
const fs = require('fs');
const OFFSET_FILE = '/data/inbox/.tg_offset';
let offset = 0;
try {
  if (fs.existsSync(OFFSET_FILE)) {
    const n = parseInt(String(fs.readFileSync(OFFSET_FILE, 'utf8')).trim(), 10);
    if (Number.isFinite(n) && n > 0) offset = n;
  }
} catch (e) { /* first run -> offset 0 */ }
return [{ json: { offset } }];

// Route inbound Telegram messages: owner-only, command-or-chat, and advance the
// polling offset so a message is never handled twice. Commands are executed
// inline (written to the vault inbox / action log); free text is marked
// needs_llm so the downstream Groq node answers it. Every reply is built
// HTML-safe because the send node uses parse_mode HTML.
const fs = require('fs');
const path = require('path');
const INBOX = '/data/inbox';
const OFFSET_FILE = path.join(INBOX, '.tg_offset');
const ACTIONS = path.join(INBOX, '.actions.jsonl');
const OWNER = (typeof $env !== 'undefined' && $env.TELEGRAM_CHAT_ID)
  ? String($env.TELEGRAM_CHAT_ID).trim() : null;

// Escape so a stray <, > or & in echoed user text can never break Telegram's
// HTML parser or inject a tag.
const esc = (s) => String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

const CHAT_SYSTEM = [
  "You are the user's Agentic Second Brain assistant, replying inside Telegram.",
  'Be warm, concise and genuinely useful - usually a few short lines, not an essay.',
  'You can also run commands; if the user wants to capture a thought or update a',
  'project, point them to: /note <text>, /touch <project>, /done <project>,',
  '/reopen <project>, /help. Never invent personal facts you were not given.',
  'Use only Telegram-friendly markup: *bold* (single asterisks) and _italics_.'
].join(' ');

// Load the "current focus" the morning nudge left behind, so a follow-up like
// "explain more" is answered about the actual nudged project rather than as
// generic chat. Absent file -> behaves as a plain assistant.
let focus = null;
try {
  const CTX = path.join(INBOX, '.tg_context.json');
  if (fs.existsSync(CTX)) focus = JSON.parse(String(fs.readFileSync(CTX, 'utf8')));
} catch (e) { focus = null; }
const hasFocus = !!(focus && ((focus.projects && focus.projects.length) || (focus.reviews && focus.reviews.length)));

const res = $input.first().json || {};
const updates = Array.isArray(res.result) ? res.result : [];
let maxId = -1;
const out = [];

for (const u of updates) {
  if (u && typeof u.update_id === 'number' && u.update_id > maxId) maxId = u.update_id;
  const msg = (u && u.message) || null;
  if (!msg) continue;                               // ignore non-message updates
  if (msg.from && msg.from.is_bot) continue;        // no-loop: ignore bots (incl. self)
  const chatId = msg.chat && msg.chat.id;
  if (chatId === undefined || chatId === null) continue;
  if (OWNER && String(chatId) !== OWNER) continue;  // owner-only (no stranger LLM bills)
  const text = String(msg.text || '').trim();
  if (!text) continue;                              // ignore stickers/photos/etc.

  if (!text.startsWith('/')) {
    let system = CHAT_SYSTEM;
    if (hasFocus) {
      system = CHAT_SYSTEM
        + ' CURRENT FOCUS - the user is following up on today\'s nudge. Focus data as JSON: '
        + JSON.stringify({ today: focus.today, projects: focus.projects, reviews: focus.reviews })
        + ' If they ask to explain more / why / how / where they left off, expand using this data and its recent_notes. If the message is clearly unrelated, answer normally without forcing the project in.';
    }
    out.push({ json: { needs_llm: true, system, user: text } });
    continue;
  }

  // ---- Command handling (mirrors the inbound-capture semantics) ----
  const m = text.match(/^\/(\w+)\s*([\s\S]*)$/);
  const cmd = (m ? m[1] : '').toLowerCase();
  const arg = m ? m[2].trim() : '';
  try { fs.mkdirSync(INBOX, { recursive: true }); } catch (e) {}

  let reply;
  if ((cmd === 'note' || cmd === 'n' || cmd === 'capture') && arg) {
    const ts = new Date();
    const slug = (arg.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 40)) || 'note';
    const fname = ts.toISOString().slice(0, 10) + '-' + ts.getTime() + '-' + slug + '.md';
    const md = '---\ntype: capture\ncreated: ' + ts.toISOString() + '\nsource: telegram\n---\n\n' + arg + '\n';
    fs.writeFileSync(path.join(INBOX, fname), md);
    reply = '📥 Captured to inbox as <i>' + esc(fname) + '</i>';
  } else if ((cmd === 'done' || cmd === 'touch' || cmd === 'did' || cmd === 'reopen') && arg) {
    const action = cmd === 'done' ? 'done' : (cmd === 'reopen' ? 'reopen' : 'touch');
    fs.appendFileSync(ACTIONS, JSON.stringify({ ts: new Date().toISOString(), action, project: arg }) + '\n');
    reply = action === 'done'
      ? '✅ Marked <i>' + esc(arg) + '</i> as done - it will not nudge you again.'
      : (action === 'reopen'
        ? '♻️ Reopened <i>' + esc(arg) + '</i> - it can nudge you again.'
        : '👍 Logged activity on <i>' + esc(arg) + '</i> - staleness clock reset.');
  } else if (cmd === 'help' || cmd === 'start') {
    reply = '<b>Second Brain</b>\nAsk me anything, or use:\n📥 /note &lt;text&gt; - capture a thought\n👍 /touch &lt;project&gt; - reset its staleness clock\n✅ /done &lt;project&gt; - stop nudging it\n♻️ /reopen &lt;project&gt; - undo a done\n❓ /help - show this';
  } else {
    reply = '🤖 Unknown or empty command. Send /help, or just ask me a question.';
  }
  out.push({ json: { needs_llm: false, reply } });
}

// Advance the offset past everything we just saw. Telegram also drops these
// server-side on the next getUpdates call carrying the higher offset.
if (maxId >= 0) {
  try { fs.mkdirSync(INBOX, { recursive: true }); } catch (e) {}
  try { fs.writeFileSync(OFFSET_FILE, String(maxId + 1)); } catch (e) {}
}

return out;

// Normalize the Groq reply for a chat answer and render it as Telegram HTML.
// Unlike the morning nudge, an empty/blocked reply does NOT throw - a chat turn
// should always answer - so we fall back to a soft message that still surfaces
// the provider reason for debugging.
const res = $input.first().json || {};
let text = '';
if (res.choices && res.choices[0] && res.choices[0].message) {
  text = res.choices[0].message.content || '';
} else if (res.candidates && res.candidates[0] && res.candidates[0].content) {
  text = (res.candidates[0].content.parts || []).map((p) => (p && p.text) || '').join('');
} else if (typeof res.content === 'string') {
  text = res.content;
}

text = String(text).trim();
const fence = text.match(/^```[a-zA-Z]*\r?\n?([\s\S]*?)\r?\n?```$/);
if (fence) text = fence[1].trim();

if (!text) {
  const reason = (res.error && res.error.message)
    || (res.choices && res.choices[0] && res.choices[0].finish_reason)
    || 'no content';
  text = '🤔 I could not generate a reply (' + reason + '). Try rephrasing, or send /help.';
}

if (text.length > 4000) text = text.slice(0, 3990) + '\n…';

// Same WhatsApp-markup -> Telegram-HTML render as the morning nudge: escape
// HTML specials FIRST, then turn *bold* / _italic_ runs into <b>/<i>.
let reply = text.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
reply = reply.replace(/\*([^*\n]+?)\*/g, '<b>$1</b>');
reply = reply.replace(/_([^_\n]+?)_/g, '<i>$1</i>');

return [{ json: { reply } }];
